// // Asynchronous reset and enable functionality
// Output X is set to 1 when the reset signal is asserted low.
// When the reset is not active (low) and enable is asserted, the output X will be assigned the logical OR of inputs A1 and A2 on the falling edge of the clock signal.
module top_module(
    input A1,
    input A2,
    input B1,
    input clk,
    input reset_n,
    input enable,
    output reg X
);always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        X <= 0;
    end else if (enable) begin
        X <= A1 & A2;
    end
end

endmodule

